def pool2d(X, pool_size=2, stride=2, mode='max'):
    """
    X: 2D feature map (H x W)
    mode: 'max' or 'avg'
    """
    H, W = len(X), len(X[0])
    oH   = (H - pool_size) // stride + 1
    oW   = (W - pool_size) // stride + 1
    out  = []
